import React from "react";
import { motion } from "framer-motion";
import "bootstrap/dist/css/bootstrap.min.css";

export default function LandingPage() {
  return (
    <div>
      {/* Navbar */}
      <nav className="navbar navbar-expand-lg navbar-light bg-light sticky-top shadow-sm">
        <div className="container">
          <a className="navbar-brand fw-bold" href="#">
            Techvruk
          </a>
          <button
            className="navbar-toggler"
            type="button"
            data-bs-toggle="collapse"
            data-bs-target="#nav"
          >
            <span className="navbar-toggler-icon"></span>
          </button>
          <div className="collapse navbar-collapse" id="nav">
            <ul className="navbar-nav ms-auto">
              <li className="nav-item">
                <a className="nav-link" href="#programs">
                  Programs
                </a>
              </li>
              <li className="nav-item">
                <a className="nav-link" href="#community">
                  Community
                </a>
              </li>
              <li className="nav-item">
                <a className="nav-link" href="#contact">
                  Contact
                </a>
              </li>
            </ul>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <section
        className="text-center text-white d-flex align-items-center"
        style={{
          height: "90vh",
          background: "linear-gradient(90deg,#2563eb,#7c3aed)",
        }}
      >
        <div className="container">
          <motion.h1
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            className="display-4 fw-bold"
          >
            Build the Future with Techvruk
          </motion.h1>
          <p className="lead mt-3">
            Empowering engineers through innovation, training, and collaboration
          </p>
          <div className="mt-4">
            <button className="btn btn-light me-3">Join Now</button>
            <button className="btn btn-outline-light">Explore Programs</button>
          </div>
        </div>
      </section>

      {/* Value Proposition */}
      <section className="py-5 text-center">
        <div className="container">
          <div className="row g-4">
            {[
              "Innovation Contests",
              "Industry Training",
              "Awards & Recognition",
              "Networking",
            ].map((item, i) => (
              <div key={i} className="col-md-3">
                <div className="card h-100 shadow-sm">
                  <div className="card-body">
                    <h5 className="card-title">{item}</h5>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* How It Works */}
      <section className="bg-light py-5 text-center">
        <div className="container">
          <h2 className="fw-bold mb-4">How It Works</h2>
          <div className="row g-4">
            {["Sign Up", "Learn & Participate", "Get Recognized"].map(
              (step, i) => (
                <div key={i} className="col-md-4">
                  <div className="p-4 bg-white shadow-sm rounded">
                    <h5>{step}</h5>
                  </div>
                </div>
              ),
            )}
          </div>
        </div>
      </section>

      {/* Programs */}
      <section id="programs" className="py-5">
        <div className="container">
          <h2 className="text-center fw-bold mb-4">Programs & Opportunities</h2>
          <div className="row g-4">
            {[1, 2, 3].map((_, i) => (
              <div key={i} className="col-md-4">
                <div className="card h-100">
                  <div className="card-body">
                    <h5 className="card-title">Program {i + 1}</h5>
                    <p className="card-text">
                      Brief details about the program.
                    </p>
                    <button className="btn btn-primary">Apply Now</button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Community */}
      <section id="community" className="bg-light py-5 text-center">
        <div className="container">
          <h2 className="fw-bold mb-4">Community & Networking</h2>
          <p>
            Connect with like-minded engineers, collaborate on projects, and
            grow together.
          </p>
        </div>
      </section>

      {/* Testimonials */}
      <section className="py-5 text-center">
        <div className="container">
          <h2 className="fw-bold mb-4">What Students Say</h2>
          <div className="row g-4">
            {["Great platform!", "Amazing experience!"].map((text, i) => (
              <div key={i} className="col-md-6">
                <div className="p-4 border rounded shadow-sm">
                  <p>"{text}"</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Stats */}
      <section className="bg-dark text-white text-center py-5">
